var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`지켜야… 해.`,JPN:`守ら……なければ。`,ENG:`Must... Protect...`,TWN:`<color=#ff3636>要……保護…</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`그걸… 가져 가선… 안돼.`,JPN:`それを……持って行っては……いけない。`,ENG:`You... mustn't... take it...`,TWN:`<color=#ff3636>不可……以把它……拿走。</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`……헉!`,JPN:`……えっ！`,ENG:`Kuh...!`,TWN:`……唔！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`지금 그 커다란 창으로 사람을 찌른 거야?`,JPN:`今、そのおっきい槍で人を突いたの？`,ENG:`Did you just stab a person with that giant spear?`,TWN:`你現在是拿那把槍在刺人嗎？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`어떡해~ 진짜 아프겠다~`,JPN:`どうしよう～めっちゃ痛そう～`,ENG:`Oh no! That must have weally hwurt...`,TWN:`怎麼辦～一定很痛～`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_REAL`,text:{KOREA:`……뭐라고?`,JPN:`……何だと？`,ENG:`...What?`,TWN:`……什麼？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`AIDE_BORDER_NULL_NULL`,text:{KOREA:`커헉……!`,JPN:`かはっ……！`,ENG:`Khhhkk!`,TWN:`咳咳……！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`AIDE_BORDER_NULL_NULL`,text:{KOREA:`큐리안…… 총사…… 대장님……`,JPN:`キュリアン……銃士……隊長……`,ENG:`Sir… General… Musketeer…`,TWN:`庫里安……隊……隊長……`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_REAL`,text:{KOREA:`데이빗……?`,JPN:`デイビッド……？`,ENG:`D-David...?`,TWN:`大衛……？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`오우. 목석처럼 굴면서 실은 조금 쌓인 거 아냐? 저런 오빠를 나라고 착각하. 다. 니?`,JPN:`わあ。無関心なふりして実はちょっと溜まってたんじゃないの？　あの人をあたしと勘違いす・る・な・ん・て？`,ENG:`Wow. Seems like maybe you got a lot of pent-up frustration? I. Can't. Believe. You thought he was me.`,TWN:`哇喔，看你一副冷靜的樣子，結果還是有稍微中招的嘛？你是不是把那位哥哥誤認為，是，我，啦？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`쿠흡……! 쿠흐흐흐흣!`,JPN:`くふっ……！　くふふふふっ！`,ENG:`Pff...! PFFFTTT!`,TWN:`嘻嘻……！呵呵呵呵！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_REAL`,text:{KOREA:`……뭐가 그렇게 재미있지?`,JPN:`……何がそんなに面白い！`,ENG:`What's so amusing to you?`,TWN:`……有什麼好笑的？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_REAL`,text:{KOREA:`성유물을 빼앗고 싶다면 맞서 싸워라. 대체 왜 이런 짓까지 하는 거냐.`,JPN:`聖遺物を奪いたいのなら正面から来い。どうしてこんなことまでするんだ。`,ENG:`If you want the Holy Relic, then fight me. Why are you playing games?`,TWN:`想搶走聖遺物的話，有本事就正面對決！到底爲什麼要做這種事？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`아. 질문 진짜 고리타분하네.`,JPN:`あ。ホントつまんない質問だわ。`,ENG:`Ugh. You're so old-fashioned.`,TWN:`啊，好老套的問題。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CYMBALS_NPC_NULL_NONAMED`,text:{KOREA:`음악 좋아하는 사람이 악기 좀 연주하겠다는데 다른 이유가 필요해?`,JPN:`音楽好きが楽器を演奏するのに何か理由が必要なわけ？`,ENG:`Does a musician need a reason to play her instrument?`,TWN:`喜歡音樂的人要演奏一下樂器，哪還需要什麼理由？`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CYMBALS_NPC_NULL_NONAMED`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_REAL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_REAL`,text:{KOREA:`잘 들어라, 허밋.`,JPN:`よく聞け、ハーミット。`,ENG:`Listen carefully, Hermit.`,TWN:`赫米特，聽著！`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_REAL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};